mapper.update:
UPDATE growth_autopilot_task
SET
    status = 'done',
    complete_time = #{completeTime},
    update_time = NOW()
WHERE id = #{id}
  AND goal_id = #{goalId}
  AND user_id = #{userId}
  AND status != 'done'

UPDATE growth_autopilot_task
SET
    status = 'done',
    complete_time = #{completeTime},
    update_time = NOW()
WHERE goal_id = #{goalId}
  AND user_id = #{userId}
  AND status = 'todo'
  AND task_date = #{date}

UPDATE growth_autopilot_task
SET
    task_date = #{newDate},
    update_time = NOW()
WHERE id = #{id}
  AND goal_id = #{goalId}
  AND user_id = #{userId}
  AND status = 'todo'

UPDATE growth_autopilot_task
SET
    status = 'missed',
    update_time = NOW()
WHERE goal_id = #{goalId}
  AND user_id = #{userId}
  AND status = 'todo'
  AND task_date < #{date}

mapper.delete:
DELETE FROM growth_autopilot_task
WHERE goal_id = #{goalId}
  AND user_id = #{userId}
  AND status = 'todo'
  AND task_date >= #{date}
